import React from 'react';

const projects = [
  { title: 'Project One', image: '/project1.png', link: '#' },
  { title: 'Project Two', image: '/project2.png', link: '#' },
];

const Projects = () => {
  return (
    <section id="projects" className="p-8 md:p-20 text-center">
      <h2 className="text-4xl font-bold mb-12">Projects</h2>
      <div className="flex flex-wrap justify-center gap-8">
        {projects.map((proj) => (
          <div key={proj.title} className="max-w-sm bg-gray-100 rounded-lg overflow-hidden">
            <img src={proj.image} alt={proj.title} className="w-full h-48 object-cover"/>
            <div className="p-4">
              <h3 className="text-2xl font-semibold mb-2">{proj.title}</h3>
              <a href={proj.link} className="text-red-600 hover:underline">View Project</a>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Projects;
